/// Prototype for user allocation function
/// @param size the allocation size in bytes
/// @param alignment the required alignment, guaranteed to be a power of 2
typedef b2AllocFcn =
    ffi.NativeFunction<
      ffi.Pointer<ffi.Void> Function(ffi.UnsignedInt size, ffi.Int alignment)
    >;

/// Prototype for user free function
/// @param mem the memory previously allocated through `b2AllocFcn`
typedef b2FreeFcn =
    ffi.NativeFunction<ffi.Void Function(ffi.Pointer<ffi.Void> mem)>;

/// Prototype for the user assert callback. Return 0 to skip the debugger break.
typedef b2AssertFcn =
    ffi.NativeFunction<
      ffi.Int Function(
        ffi.Pointer<ffi.Char> condition,
        ffi.Pointer<ffi.Char> fileName,
        ffi.Int lineNumber,
      )
    >;

/// Version numbering scheme.
/// See https://semver.org/
final class b2Version extends ffi.Struct {
  /// Significant changes
  @ffi.Int()
  external int major;

  /// Incremental changes
  @ffi.Int()
  external int minor;

  /// Bug fixes
  @ffi.Int()
  external int revision;
}

/// 2D vector
/// This can be used to represent a point or free vector
final class b2Vec2 extends ffi.Struct {
  /// coordinates
  @ffi.Float()
  external double x;

  @ffi.Float()
  external double y;
}

/// Cosine and sine pair
/// This uses a custom implementation designed for cross-platform determinism
final class b2CosSin extends ffi.Struct {
  /// cosine and sine
  @ffi.Float()
  external double cosine;

  @ffi.Float()
  external double sine;
}

/// 2D rotation
/// This is similar to using a complex number for rotation
final class b2Rot extends ffi.Struct {
  /// cosine and sine
  @ffi.Float()
  external double c;

  @ffi.Float()
  external double s;
}

/// A 2D rigid transform
final class b2Transform extends ffi.Struct {
  external b2Vec2 p;

  external b2Rot q;
}

/// A 2-by-2 Matrix
final class b2Mat22 extends ffi.Struct {
  /// columns
  external b2Vec2 cx;

  external b2Vec2 cy;
}

/// Axis-aligned bounding box
final class b2AABB extends ffi.Struct {
  external b2Vec2 lowerBound;

  external b2Vec2 upperBound;
}

/// separation = dot(normal, point) - offset
final class b2Plane extends ffi.Struct {
  external b2Vec2 normal;

  @ffi.Float()
  external double offset;
}

/// Used to warm start the GJK simplex. If you call this function multiple times with nearby
/// transforms this might improve performance. Otherwise you can zero initialize this.
/// The distance cache must be initialized to zero on the first call.
/// Users should generally just zero initialize this structure for each call.
final class b2SimplexCache extends ffi.Struct {
  /// The number of stored simplex points
  @ffi.Uint16()
  external int count;

  /// The cached simplex indices on shape A
  @ffi.Array.multi([3])
  external ffi.Array<ffi.Uint8> indexA;

  /// The cached simplex indices on shape B
  @ffi.Array.multi([3])
  external ffi.Array<ffi.Uint8> indexB;
}

/// A convex hull. Used to create convex polygons.
/// @warning Do not modify these values directly, instead use b2ComputeHull()
final class b2Hull extends ffi.Struct {
  /// The final points of the hull
  @ffi.Array.multi([8])
  external ffi.Array<b2Vec2> points;

  /// The number of points
  @ffi.Int()
  external int count;
}

/// Low level ray cast input data
final class b2RayCastInput extends ffi.Struct {
  /// Start point of the ray cast
  external b2Vec2 origin;

  /// Translation of the ray cast
  external b2Vec2 translation;

  /// The maximum fraction of the translation to consider, typically 1
  @ffi.Float()
  external double maxFraction;
}

/// A distance proxy is used by the GJK algorithm. It encapsulates any shape.
/// You can provide between 1 and B2_MAX_POLYGON_VERTICES and a radius.
final class b2ShapeProxy extends ffi.Struct {
  /// The point cloud
  @ffi.Array.multi([8])
  external ffi.Array<b2Vec2> points;

  /// The number of points. Must be greater than 0.
  @ffi.Int()
  external int count;

  /// The external radius of the point cloud. May be zero.
  @ffi.Float()
  external double radius;
}

/// Low level shape cast input in generic form. This allows casting an arbitrary point
/// cloud wrap with a radius. For example, a circle is a single point with a non-zero radius.
/// A capsule is two points with a non-zero radius. A box is four points with a zero radius.
final class b2ShapeCastInput extends ffi.Struct {
  /// A generic shape
  external b2ShapeProxy proxy;

  /// The translation of the shape cast
  external b2Vec2 translation;

  /// The maximum fraction of the translation to consider, typically 1
  @ffi.Float()
  external double maxFraction;

  /// Allow shape cast to encroach when initially touching. This only works if the radius is greater than zero.
  @ffi.Bool()
  external bool canEncroach;
}

/// Low level ray cast or shape-cast output data. Returns a zero fraction and normal in the case of initial overlap.
final class b2CastOutput extends ffi.Struct {
  /// The surface normal at the hit point
  external b2Vec2 normal;

  /// The surface hit point
  external b2Vec2 point;

  /// The fraction of the input translation at collision
  @ffi.Float()
  external double fraction;

  /// The number of iterations used
  @ffi.Int()
  external int iterations;

  /// Did the cast hit?
  @ffi.Bool()
  external bool hit;
}

/// This holds the mass data computed for a shape.
final class b2MassData extends ffi.Struct {
  /// The mass of the shape, usually in kilograms.
  @ffi.Float()
  external double mass;

  /// The position of the shape's centroid relative to the shape's origin.
  external b2Vec2 center;

  /// The rotational inertia of the shape about the local origin.
  @ffi.Float()
  external double rotationalInertia;
}

/// A solid circle
final class b2Circle extends ffi.Struct {
  /// The local center
  external b2Vec2 center;

  /// The radius
  @ffi.Float()
  external double radius;
}

/// A solid capsule can be viewed as two semicircles connected
/// by a rectangle.
final class b2Capsule extends ffi.Struct {
  /// Local center of the first semicircle
  external b2Vec2 center1;

  /// Local center of the second semicircle
  external b2Vec2 center2;

  /// The radius of the semicircles
  @ffi.Float()
  external double radius;
}

/// A solid convex polygon. It is assumed that the interior of the polygon is to
/// the left of each edge.
/// Polygons have a maximum number of vertices equal to B2_MAX_POLYGON_VERTICES.
/// In most cases you should not need many vertices for a convex polygon.
/// @warning DO NOT fill this out manually, instead use a helper function like
/// b2MakePolygon or b2MakeBox.
final class b2Polygon extends ffi.Struct {
  /// The polygon vertices
  @ffi.Array.multi([8])
  external ffi.Array<b2Vec2> vertices;

  /// The outward normal vectors of the polygon sides
  @ffi.Array.multi([8])
  external ffi.Array<b2Vec2> normals;

  /// The centroid of the polygon
  external b2Vec2 centroid;

  /// The external radius for rounded polygons
  @ffi.Float()
  external double radius;

  /// The number of polygon vertices
  @ffi.Int()
  external int count;
}

/// A line segment with two-sided collision.
final class b2Segment extends ffi.Struct {
  /// The first point
  external b2Vec2 point1;

  /// The second point
  external b2Vec2 point2;
}

/// A line segment with one-sided collision. Only collides on the right side.
/// Several of these are generated for a chain shape.
/// ghost1 -> point1 -> point2 -> ghost2
final class b2ChainSegment extends ffi.Struct {
  /// The tail ghost vertex
  external b2Vec2 ghost1;

  /// The line segment
  external b2Segment segment;

  /// The head ghost vertex
  external b2Vec2 ghost2;

  /// The owning chain shape index (internal usage only)
  @ffi.Int()
  external int chainId;
}

/// Result of computing the distance between two line segments
final class b2SegmentDistanceResult extends ffi.Struct {
  /// The closest point on the first segment
  external b2Vec2 closest1;

  /// The closest point on the second segment
  external b2Vec2 closest2;

  /// The barycentric coordinate on the first segment
  @ffi.Float()
  external double fraction1;

  /// The barycentric coordinate on the second segment
  @ffi.Float()
  external double fraction2;

  /// The squared distance between the closest points
  @ffi.Float()
  external double distanceSquared;
}

/// Input for b2ShapeDistance
final class b2DistanceInput extends ffi.Struct {
  /// The proxy for shape A
  external b2ShapeProxy proxyA;

  /// The proxy for shape B
  external b2ShapeProxy proxyB;

  /// The world transform for shape A
  external b2Transform transformA;

  /// The world transform for shape B
  external b2Transform transformB;

  /// Should the proxy radius be considered?
  @ffi.Bool()
  external bool useRadii;
}

/// Output for b2ShapeDistance
final class b2DistanceOutput extends ffi.Struct {
  /// < Closest point on shapeA
  external b2Vec2 pointA;

  /// < Closest point on shapeB
  external b2Vec2 pointB;

  /// < Normal vector that points from A to B. Invalid if distance is zero.
  external b2Vec2 normal;

  /// < The final distance, zero if overlapped
  @ffi.Float()
  external double distance;

  /// < Number of GJK iterations used
  @ffi.Int()
  external int iterations;

  /// < The number of simplexes stored in the simplex array
  @ffi.Int()
  external int simplexCount;
}

/// Simplex vertex for debugging the GJK algorithm
final class b2SimplexVertex extends ffi.Struct {
  /// < support point in proxyA
  external b2Vec2 wA;

  /// < support point in proxyB
  external b2Vec2 wB;

  /// < wB - wA
  external b2Vec2 w;

  /// < barycentric coordinate for closest point
  @ffi.Float()
  external double a;

  /// < wA index
  @ffi.Int()
  external int indexA;

  /// < wB index
  @ffi.Int()
  external int indexB;
}

/// Simplex from the GJK algorithm
final class b2Simplex extends ffi.Struct {
  /// < vertices
  external b2SimplexVertex v1;

  external b2SimplexVertex v2;

  external b2SimplexVertex v3;

  /// < number of valid vertices
  @ffi.Int()
  external int count;
}

/// Input parameters for b2ShapeCast
final class b2ShapeCastPairInput extends ffi.Struct {
  /// < The proxy for shape A
  external b2ShapeProxy proxyA;

  /// < The proxy for shape B
  external b2ShapeProxy proxyB;

  /// < The world transform for shape A
  external b2Transform transformA;

  /// < The world transform for shape B
  external b2Transform transformB;

  /// < The translation of shape B
  external b2Vec2 translationB;

  /// < The fraction of the translation to consider, typically 1
  @ffi.Float()
  external double maxFraction;

  /// < Allows shapes with a radius to move slightly closer if already touching
  @ffi.Bool()
  external bool canEncroach;
}

/// This describes the motion of a body/shape for TOI computation. Shapes are defined with respect to the body origin,
/// which may not coincide with the center of mass. However, to support dynamics we must interpolate the center of mass
/// position.
final class b2Sweep extends ffi.Struct {
  /// < Local center of mass position
  external b2Vec2 localCenter;

  /// < Starting center of mass world position
  external b2Vec2 c1;

  /// < Ending center of mass world position
  external b2Vec2 c2;

  /// < Starting world rotation
  external b2Rot q1;

  /// < Ending world rotation
  external b2Rot q2;
}

/// Input parameters for b2TimeOfImpact
final class b2TOIInput extends ffi.Struct {
  /// < The proxy for shape A
  external b2ShapeProxy proxyA;

  /// < The proxy for shape B
  external b2ShapeProxy proxyB;

  /// < The movement of shape A
  external b2Sweep sweepA;

  /// < The movement of shape B
  external b2Sweep sweepB;

  /// < Defines the sweep interval [0, maxFraction]
  @ffi.Float()
  external double maxFraction;
}

/// Describes the TOI output
enum b2TOIState {
  b2_toiStateUnknown(0),
  b2_toiStateFailed(1),
  b2_toiStateOverlapped(2),
  b2_toiStateHit(3),
  b2_toiStateSeparated(4);

  final int value;
  const b2TOIState(this.value);

  static b2TOIState fromValue(int value) => switch (value) {
    0 => b2_toiStateUnknown,
    1 => b2_toiStateFailed,
    2 => b2_toiStateOverlapped,
    3 => b2_toiStateHit,
    4 => b2_toiStateSeparated,
    _ => throw ArgumentError('Unknown value for b2TOIState: $value'),
  };
}

/// Output parameters for b2TimeOfImpact.
final class b2TOIOutput extends ffi.Struct {
  /// < The type of result
  @ffi.UnsignedInt()
  external int stateAsInt;

  b2TOIState get state => b2TOIState.fromValue(stateAsInt);

  /// < The sweep time of the collision
  @ffi.Float()
  external double fraction;
}

/// A manifold point is a contact point belonging to a contact manifold.
/// It holds details related to the geometry and dynamics of the contact points.
/// Box2D uses speculative collision so some contact points may be separated.
/// You may use the totalNormalImpulse to determine if there was an interaction during
/// the time step.
final class b2ManifoldPoint extends ffi.Struct {
  /// Location of the contact point in world space. Subject to precision loss at large coordinates.
  /// @note Should only be used for debugging.
  external b2Vec2 point;

  /// Location of the contact point relative to shapeA's origin in world space
  /// @note When used internally to the Box2D solver, this is relative to the body center of mass.
  external b2Vec2 anchorA;

  /// Location of the contact point relative to shapeB's origin in world space
  /// @note When used internally to the Box2D solver, this is relative to the body center of mass.
  external b2Vec2 anchorB;

  /// The separation of the contact point, negative if penetrating
  @ffi.Float()
  external double separation;

  /// The impulse along the manifold normal vector.
  @ffi.Float()
  external double normalImpulse;

  /// The friction impulse
  @ffi.Float()
  external double tangentImpulse;

  /// The total normal impulse applied across sub-stepping and restitution. This is important
  /// to identify speculative contact points that had an interaction in the time step.
  @ffi.Float()
  external double totalNormalImpulse;

  /// Relative normal velocity pre-solve. Used for hit events. If the normal impulse is
  /// zero then there was no hit. Negative means shapes are approaching.
  @ffi.Float()
  external double normalVelocity;

  /// Uniquely identifies a contact point between two shapes
  @ffi.Uint16()
  external int id;

  /// Did this contact point exist the previous step?
  @ffi.Bool()
  external bool persisted;
}

/// A contact manifold describes the contact points between colliding shapes.
/// @note Box2D uses speculative collision so some contact points may be separated.
final class b2Manifold extends ffi.Struct {
  /// The unit normal vector in world space, points from shape A to bodyB
  external b2Vec2 normal;

  /// Angular impulse applied for rolling resistance. N * m * s = kg * m^2 / s
  @ffi.Float()
  external double rollingImpulse;

  /// The manifold points, up to two are possible in 2D
  @ffi.Array.multi([2])
  external ffi.Array<b2ManifoldPoint> points;

  /// The number of contacts points, will be 0, 1, or 2
  @ffi.Int()
  external int pointCount;
}

final class b2TreeNode extends ffi.Opaque {}

/// The dynamic tree structure. This should be considered private data.
/// It is placed here for performance reasons.
final class b2DynamicTree extends ffi.Struct {
  /// The tree nodes
  external ffi.Pointer<b2TreeNode> nodes;

  /// The root index
  @ffi.Int()
  external int root;

  /// The number of nodes
  @ffi.Int()
  external int nodeCount;

  /// The allocated node space
  @ffi.Int()
  external int nodeCapacity;

  /// Node free list
  @ffi.Int()
  external int freeList;

  /// Number of proxies created
  @ffi.Int()
  external int proxyCount;

  /// Leaf indices for rebuild
  external ffi.Pointer<ffi.Int> leafIndices;

  /// Leaf bounding boxes for rebuild
  external ffi.Pointer<b2AABB> leafBoxes;

  /// Leaf bounding box centers for rebuild
  external ffi.Pointer<b2Vec2> leafCenters;

  /// Bins for sorting during rebuild
  external ffi.Pointer<ffi.Int> binIndices;

  /// Allocated space for rebuilding
  @ffi.Int()
  external int rebuildCapacity;
}

