/// Task interface
/// This is prototype for a Box2D task. Your task system is expected to invoke the Box2D task with these arguments.
/// The task spans a range of the parallel-for: [startIndex, endIndex)
/// The worker index must correctly identify each worker in the user thread pool, expected in [0, workerCount).
/// A worker must only exist on only one thread at a time and is analogous to the thread index.
/// The task context is the context pointer sent from Box2D when it is enqueued.
/// The startIndex and endIndex are expected in the range [0, itemCount) where itemCount is the argument to b2EnqueueTaskCallback
/// below. Box2D expects startIndex < endIndex and will execute a loop like this:
///
/// @code{.c}
/// for (int i = startIndex; i < endIndex; ++i)
/// {
/// DoWork();
/// }
/// @endcode
/// @ingroup world
typedef b2TaskCallback =
    ffi.NativeFunction<
      ffi.Void Function(
        ffi.Int startIndex,
        ffi.Int endIndex,
        ffi.Uint32 workerIndex,
        ffi.Pointer<ffi.Void> taskContext,
      )
    >;

/// These functions can be provided to Box2D to invoke a task system. These are designed to work well with enkiTS.
/// Returns a pointer to the user's task object. May be nullptr. A nullptr indicates to Box2D that the work was executed
/// serially within the callback and there is no need to call b2FinishTaskCallback.
/// The itemCount is the number of Box2D work items that are to be partitioned among workers by the user's task system.
/// This is essentially a parallel-for. The minRange parameter is a suggestion of the minimum number of items to assign
/// per worker to reduce overhead. For example, suppose the task is small and that itemCount is 16. A minRange of 8 suggests
/// that your task system should split the work items among just two workers, even if you have more available.
/// In general the range [startIndex, endIndex) send to b2TaskCallback should obey:
/// endIndex - startIndex >= minRange
/// The exception of course is when itemCount < minRange.
/// @ingroup world
typedef b2EnqueueTaskCallback =
    ffi.NativeFunction<
      ffi.Pointer<ffi.Void> Function(
        ffi.Pointer<b2TaskCallback> task,
        ffi.Int itemCount,
        ffi.Int minRange,
        ffi.Pointer<ffi.Void> taskContext,
        ffi.Pointer<ffi.Void> userContext,
      )
    >;

/// Finishes a user task object that wraps a Box2D task.
/// @ingroup world
typedef b2FinishTaskCallback =
    ffi.NativeFunction<
      ffi.Void Function(
        ffi.Pointer<ffi.Void> userTask,
        ffi.Pointer<ffi.Void> userContext,
      )
    >;

/// Optional friction mixing callback. This intentionally provides no context objects because this is called
/// from a worker thread.
/// @warning This function should not attempt to modify Box2D state or user application state.
/// @ingroup world
typedef b2FrictionCallback =
    ffi.NativeFunction<
      ffi.Float Function(
        ffi.Float frictionA,
        ffi.Int userMaterialIdA,
        ffi.Float frictionB,
        ffi.Int userMaterialIdB,
      )
    >;

/// Optional restitution mixing callback. This intentionally provides no context objects because this is called
/// from a worker thread.
/// @warning This function should not attempt to modify Box2D state or user application state.
/// @ingroup world
typedef b2RestitutionCallback =
    ffi.NativeFunction<
      ffi.Float Function(
        ffi.Float restitutionA,
        ffi.Int userMaterialIdA,
        ffi.Float restitutionB,
        ffi.Int userMaterialIdB,
      )
    >;

/// Result from b2World_RayCastClosest
/// If there is initial overlap the fraction and normal will be zero while the point is an arbitrary point in the overlap region.
/// @ingroup world
final class b2RayResult extends ffi.Struct {
  external b2ShapeId shapeId;

  external b2Vec2 point;

  external b2Vec2 normal;

  @ffi.Float()
  external double fraction;

  @ffi.Int()
  external int nodeVisits;

  @ffi.Int()
  external int leafVisits;

  @ffi.Bool()
  external bool hit;
}

/// World definition used to create a simulation world.
/// Must be initialized using b2DefaultWorldDef().
/// @ingroup world
final class b2WorldDef extends ffi.Struct {
  /// Gravity vector. Box2D has no up-vector defined.
  external b2Vec2 gravity;

  /// Restitution speed threshold, usually in m/s. Collisions above this
  /// speed have restitution applied (will bounce).
  @ffi.Float()
  external double restitutionThreshold;

  /// Threshold speed for hit events. Usually meters per second.
  @ffi.Float()
  external double hitEventThreshold;

  /// Contact stiffness. Cycles per second. Increasing this increases the speed of overlap recovery, but can introduce jitter.
  @ffi.Float()
  external double contactHertz;

  /// Contact bounciness. Non-dimensional. You can speed up overlap recovery by decreasing this with
  /// the trade-off that overlap resolution becomes more energetic.
  @ffi.Float()
  external double contactDampingRatio;

  /// This parameter controls how fast overlap is resolved and usually has units of meters per second. This only
  /// puts a cap on the resolution speed. The resolution speed is increased by increasing the hertz and/or
  /// decreasing the damping ratio.
  @ffi.Float()
  external double maxContactPushSpeed;

  /// Maximum linear speed. Usually meters per second.
  @ffi.Float()
  external double maximumLinearSpeed;

  /// Optional mixing callback for friction. The default uses sqrt(frictionA * frictionB).
  external ffi.Pointer<b2FrictionCallback> frictionCallback;

  /// Optional mixing callback for restitution. The default uses max(restitutionA, restitutionB).
  external ffi.Pointer<b2RestitutionCallback> restitutionCallback;

  /// Can bodies go to sleep to improve performance
  @ffi.Bool()
  external bool enableSleep;

  /// Enable continuous collision
  @ffi.Bool()
  external bool enableContinuous;

  /// Number of workers to use with the provided task system. Box2D performs best when using only
  /// performance cores and accessing a single L2 cache. Efficiency cores and hyper-threading provide
  /// little benefit and may even harm performance.
  /// @note Box2D does not create threads. This is the number of threads your applications has created
  /// that you are allocating to b2World_Step.
  /// @warning Do not modify the default value unless you are also providing a task system and providing
  /// task callbacks (enqueueTask and finishTask).
  @ffi.Int()
  external int workerCount;

  /// Function to spawn tasks
  external ffi.Pointer<b2EnqueueTaskCallback> enqueueTask;

  /// Function to finish a task
  external ffi.Pointer<b2FinishTaskCallback> finishTask;

  /// User context that is provided to enqueueTask and finishTask
  external ffi.Pointer<ffi.Void> userTaskContext;

  /// User data
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// The body simulation type.
/// Each body is one of these three types. The type determines how the body behaves in the simulation.
/// @ingroup body
enum b2BodyType {
  /// zero mass, zero velocity, may be manually moved
  b2_staticBody(0),

  /// zero mass, velocity set by user, moved by solver
  b2_kinematicBody(1),

  /// positive mass, velocity determined by forces, moved by solver
  b2_dynamicBody(2),

  /// number of body types
  b2_bodyTypeCount(3);

  final int value;
  const b2BodyType(this.value);

  static b2BodyType fromValue(int value) => switch (value) {
    0 => b2_staticBody,
    1 => b2_kinematicBody,
    2 => b2_dynamicBody,
    3 => b2_bodyTypeCount,
    _ => throw ArgumentError('Unknown value for b2BodyType: $value'),
  };
}

/// A body definition holds all the data needed to construct a rigid body.
/// You can safely re-use body definitions. Shapes are added to a body after construction.
/// Body definitions are temporary objects used to bundle creation parameters.
/// Must be initialized using b2DefaultBodyDef().
/// @ingroup body
final class b2BodyDef extends ffi.Struct {
  /// The body type: static, kinematic, or dynamic.
  @ffi.UnsignedInt()
  external int typeAsInt;

  b2BodyType get type => b2BodyType.fromValue(typeAsInt);

  /// The initial world position of the body. Bodies should be created with the desired position.
  /// @note Creating bodies at the origin and then moving them nearly doubles the cost of body creation, especially
  /// if the body is moved after shapes have been added.
  external b2Vec2 position;

  /// The initial world rotation of the body. Use b2MakeRot() if you have an angle.
  external b2Rot rotation;

  /// The initial linear velocity of the body's origin. Usually in meters per second.
  external b2Vec2 linearVelocity;

  /// The initial angular velocity of the body. Radians per second.
  @ffi.Float()
  external double angularVelocity;

  /// Linear damping is used to reduce the linear velocity. The damping parameter
  /// can be larger than 1 but the damping effect becomes sensitive to the
  /// time step when the damping parameter is large.
  /// Generally linear damping is undesirable because it makes objects move slowly
  /// as if they are floating.
  @ffi.Float()
  external double linearDamping;

  /// Angular damping is used to reduce the angular velocity. The damping parameter
  /// can be larger than 1.0f but the damping effect becomes sensitive to the
  /// time step when the damping parameter is large.
  /// Angular damping can be use slow down rotating bodies.
  @ffi.Float()
  external double angularDamping;

  /// Scale the gravity applied to this body. Non-dimensional.
  @ffi.Float()
  external double gravityScale;

  /// Sleep speed threshold, default is 0.05 meters per second
  @ffi.Float()
  external double sleepThreshold;

  /// Optional body name for debugging. Up to 31 characters (excluding null termination)
  external ffi.Pointer<ffi.Char> name;

  /// Use this to store application specific body data.
  external ffi.Pointer<ffi.Void> userData;

  /// Set this flag to false if this body should never fall asleep.
  @ffi.Bool()
  external bool enableSleep;

  /// Is this body initially awake or sleeping?
  @ffi.Bool()
  external bool isAwake;

  /// Should this body be prevented from rotating? Useful for characters.
  @ffi.Bool()
  external bool fixedRotation;

  /// Treat this body as high speed object that performs continuous collision detection
  /// against dynamic and kinematic bodies, but not other bullet bodies.
  /// @warning Bullets should be used sparingly. They are not a solution for general dynamic-versus-dynamic
  /// continuous collision. They may interfere with joint constraints.
  @ffi.Bool()
  external bool isBullet;

  /// Used to disable a body. A disabled body does not move or collide.
  @ffi.Bool()
  external bool isEnabled;

  /// This allows this body to bypass rotational speed limits. Should only be used
  /// for circular objects, like wheels.
  @ffi.Bool()
  external bool allowFastRotation;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// This is used to filter collision on shapes. It affects shape-vs-shape collision
/// and shape-versus-query collision (such as b2World_CastRay).
/// @ingroup shape
final class b2Filter extends ffi.Struct {
  /// The collision category bits. Normally you would just set one bit. The category bits should
  /// represent your application object types. For example:
  /// @code{.cpp}
  /// enum MyCategories
  /// {
  /// Static  = 0x00000001,
  /// Dynamic = 0x00000002,
  /// Debris  = 0x00000004,
  /// Player  = 0x00000008,
  /// // etc
  /// };
  /// @endcode
  @ffi.Uint64()
  external int categoryBits;

  /// The collision mask bits. This states the categories that this
  /// shape would accept for collision.
  /// For example, you may want your player to only collide with static objects
  /// and other players.
  /// @code{.c}
  /// maskBits = Static | Player;
  /// @endcode
  @ffi.Uint64()
  external int maskBits;

  /// Collision groups allow a certain group of objects to never collide (negative)
  /// or always collide (positive). A group index of zero has no effect. Non-zero group filtering
  /// always wins against the mask bits.
  /// For example, you may want ragdolls to collide with other ragdolls but you don't want
  /// ragdoll self-collision. In this case you would give each ragdoll a unique negative group index
  /// and apply that group index to all shapes on the ragdoll.
  @ffi.Int()
  external int groupIndex;
}

/// The query filter is used to filter collisions between queries and shapes. For example,
/// you may want a ray-cast representing a projectile to hit players and the static environment
/// but not debris.
/// @ingroup shape
final class b2QueryFilter extends ffi.Struct {
  /// The collision category bits of this query. Normally you would just set one bit.
  @ffi.Uint64()
  external int categoryBits;

  /// The collision mask bits. This states the shape categories that this
  /// query would accept for collision.
  @ffi.Uint64()
  external int maskBits;
}

/// Shape type
/// @ingroup shape
enum b2ShapeType {
  /// A circle with an offset
  b2_circleShape(0),

  /// A capsule is an extruded circle
  b2_capsuleShape(1),

  /// A line segment
  b2_segmentShape(2),

  /// A convex polygon
  b2_polygonShape(3),

  /// A line segment owned by a chain shape
  b2_chainSegmentShape(4),

  /// The number of shape types
  b2_shapeTypeCount(5);

  final int value;
  const b2ShapeType(this.value);

  static b2ShapeType fromValue(int value) => switch (value) {
    0 => b2_circleShape,
    1 => b2_capsuleShape,
    2 => b2_segmentShape,
    3 => b2_polygonShape,
    4 => b2_chainSegmentShape,
    5 => b2_shapeTypeCount,
    _ => throw ArgumentError('Unknown value for b2ShapeType: $value'),
  };
}

/// Surface materials allow chain shapes to have per segment surface properties.
/// @ingroup shape
final class b2SurfaceMaterial extends ffi.Struct {
  /// The Coulomb (dry) friction coefficient, usually in the range [0,1].
  @ffi.Float()
  external double friction;

  /// The coefficient of restitution (bounce) usually in the range [0,1].
  /// https://en.wikipedia.org/wiki/Coefficient_of_restitution
  @ffi.Float()
  external double restitution;

  /// The rolling resistance usually in the range [0,1].
  @ffi.Float()
  external double rollingResistance;

  /// The tangent speed for conveyor belts
  @ffi.Float()
  external double tangentSpeed;

  /// User material identifier. This is passed with query results and to friction and restitution
  /// combining functions. It is not used internally.
  @ffi.Int()
  external int userMaterialId;

  /// Custom debug draw color.
  @ffi.Uint32()
  external int customColor;
}

/// Used to create a shape.
/// This is a temporary object used to bundle shape creation parameters. You may use
/// the same shape definition to create multiple shapes.
/// Must be initialized using b2DefaultShapeDef().
/// @ingroup shape
final class b2ShapeDef extends ffi.Struct {
  /// Use this to store application specific shape data.
  external ffi.Pointer<ffi.Void> userData;

  /// The surface material for this shape.
  external b2SurfaceMaterial material;

  /// The density, usually in kg/m^2.
  /// This is not part of the surface material because this is for the interior, which may have
  /// other considerations, such as being hollow. For example a wood barrel may be hollow or full of water.
  @ffi.Float()
  external double density;

  /// Collision filtering data.
  external b2Filter filter;

  /// A sensor shape generates overlap events but never generates a collision response.
  /// Sensors do not have continuous collision. Instead, use a ray or shape cast for those scenarios.
  /// Sensors still contribute to the body mass if they have non-zero density.
  /// @note Sensor events are disabled by default.
  /// @see enableSensorEvents
  @ffi.Bool()
  external bool isSensor;

  /// Enable sensor events for this shape. This applies to sensors and non-sensors. False by default, even for sensors.
  @ffi.Bool()
  external bool enableSensorEvents;

  /// Enable contact events for this shape. Only applies to kinematic and dynamic bodies. Ignored for sensors. False by default.
  @ffi.Bool()
  external bool enableContactEvents;

  /// Enable hit events for this shape. Only applies to kinematic and dynamic bodies. Ignored for sensors. False by default.
  @ffi.Bool()
  external bool enableHitEvents;

  /// Enable pre-solve contact events for this shape. Only applies to dynamic bodies. These are expensive
  /// and must be carefully handled due to threading. Ignored for sensors.
  @ffi.Bool()
  external bool enablePreSolveEvents;

  /// When shapes are created they will scan the environment for collision the next time step. This can significantly slow down
  /// static body creation when there are many static shapes.
  /// This is flag is ignored for dynamic and kinematic shapes which always invoke contact creation.
  @ffi.Bool()
  external bool invokeContactCreation;

  /// Should the body update the mass properties when this shape is created. Default is true.
  @ffi.Bool()
  external bool updateBodyMass;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// Used to create a chain of line segments. This is designed to eliminate ghost collisions with some limitations.
/// - chains are one-sided
/// - chains have no mass and should be used on static bodies
/// - chains have a counter-clockwise winding order (normal points right of segment direction)
/// - chains are either a loop or open
/// - a chain must have at least 4 points
/// - the distance between any two points must be greater than B2_LINEAR_SLOP
/// - a chain shape should not self intersect (this is not validated)
/// - an open chain shape has NO COLLISION on the first and final edge
/// - you may overlap two open chains on their first three and/or last three points to get smooth collision
/// - a chain shape creates multiple line segment shapes on the body
/// https://en.wikipedia.org/wiki/Polygonal_chain
/// Must be initialized using b2DefaultChainDef().
/// @warning Do not use chain shapes unless you understand the limitations. This is an advanced feature.
/// @ingroup shape
final class b2ChainDef extends ffi.Struct {
  /// Use this to store application specific shape data.
  external ffi.Pointer<ffi.Void> userData;

  /// An array of at least 4 points. These are cloned and may be temporary.
  external ffi.Pointer<b2Vec2> points;

  /// The point count, must be 4 or more.
  @ffi.Int()
  external int count;

  /// Surface materials for each segment. These are cloned.
  external ffi.Pointer<b2SurfaceMaterial> materials;

  /// The material count. Must be 1 or count. This allows you to provide one
  /// material for all segments or a unique material per segment.
  @ffi.Int()
  external int materialCount;

  /// Contact filtering data.
  external b2Filter filter;

  /// Indicates a closed chain formed by connecting the first and last points
  @ffi.Bool()
  external bool isLoop;

  /// Enable sensors to detect this chain. False by default.
  @ffi.Bool()
  external bool enableSensorEvents;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

