/// Joint type enumeration
///
/// This is useful because all joint types use b2JointId and sometimes you
/// want to get the type of a joint.
/// @ingroup joint
enum b2JointType {
  b2_distanceJoint(0),
  b2_filterJoint(1),
  b2_motorJoint(2),
  b2_mouseJoint(3),
  b2_prismaticJoint(4),
  b2_revoluteJoint(5),
  b2_weldJoint(6),
  b2_wheelJoint(7);

  final int value;
  const b2JointType(this.value);

  static b2JointType fromValue(int value) => switch (value) {
    0 => b2_distanceJoint,
    1 => b2_filterJoint,
    2 => b2_motorJoint,
    3 => b2_mouseJoint,
    4 => b2_prismaticJoint,
    5 => b2_revoluteJoint,
    6 => b2_weldJoint,
    7 => b2_wheelJoint,
    _ => throw ArgumentError('Unknown value for b2JointType: $value'),
  };
}

/// Distance joint definition
///
/// This requires defining an anchor point on both
/// bodies and the non-zero distance of the distance joint. The definition uses
/// local anchor points so that the initial configuration can violate the
/// constraint slightly. This helps when saving and loading a game.
/// @ingroup distance_joint
final class b2DistanceJointDef extends ffi.Struct {
  /// The first attached body
  external b2BodyId bodyIdA;

  /// The second attached body
  external b2BodyId bodyIdB;

  /// The local anchor point relative to bodyA's origin
  external b2Vec2 localAnchorA;

  /// The local anchor point relative to bodyB's origin
  external b2Vec2 localAnchorB;

  /// The rest length of this joint. Clamped to a stable minimum value.
  @ffi.Float()
  external double length;

  /// Enable the distance constraint to behave like a spring. If false
  /// then the distance joint will be rigid, overriding the limit and motor.
  @ffi.Bool()
  external bool enableSpring;

  /// The spring linear stiffness Hertz, cycles per second
  @ffi.Float()
  external double hertz;

  /// The spring linear damping ratio, non-dimensional
  @ffi.Float()
  external double dampingRatio;

  /// Enable/disable the joint limit
  @ffi.Bool()
  external bool enableLimit;

  /// Minimum length. Clamped to a stable minimum value.
  @ffi.Float()
  external double minLength;

  /// Maximum length. Must be greater than or equal to the minimum length.
  @ffi.Float()
  external double maxLength;

  /// Enable/disable the joint motor
  @ffi.Bool()
  external bool enableMotor;

  /// The maximum motor force, usually in newtons
  @ffi.Float()
  external double maxMotorForce;

  /// The desired motor speed, usually in meters per second
  @ffi.Float()
  external double motorSpeed;

  /// Set this flag to true if the attached bodies should collide
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// A motor joint is used to control the relative motion between two bodies
///
/// A typical usage is to control the movement of a dynamic body with respect to the ground.
/// @ingroup motor_joint
final class b2MotorJointDef extends ffi.Struct {
  /// The first attached body
  external b2BodyId bodyIdA;

  /// The second attached body
  external b2BodyId bodyIdB;

  /// Position of bodyB minus the position of bodyA, in bodyA's frame
  external b2Vec2 linearOffset;

  /// The bodyB angle minus bodyA angle in radians
  @ffi.Float()
  external double angularOffset;

  /// The maximum motor force in newtons
  @ffi.Float()
  external double maxForce;

  /// The maximum motor torque in newton-meters
  @ffi.Float()
  external double maxTorque;

  /// Position correction factor in the range [0,1]
  @ffi.Float()
  external double correctionFactor;

  /// Set this flag to true if the attached bodies should collide
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// A mouse joint is used to make a point on a body track a specified world point.
///
/// This a soft constraint and allows the constraint to stretch without
/// applying huge forces. This also applies rotation constraint heuristic to improve control.
/// @ingroup mouse_joint
final class b2MouseJointDef extends ffi.Struct {
  /// The first attached body. This is assumed to be static.
  external b2BodyId bodyIdA;

  /// The second attached body.
  external b2BodyId bodyIdB;

  /// The initial target point in world space
  external b2Vec2 target;

  /// Stiffness in hertz
  @ffi.Float()
  external double hertz;

  /// Damping ratio, non-dimensional
  @ffi.Float()
  external double dampingRatio;

  /// Maximum force, typically in newtons
  @ffi.Float()
  external double maxForce;

  /// Set this flag to true if the attached bodies should collide.
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// A filter joint is used to disable collision between two specific bodies.
///
/// @ingroup filter_joint
final class b2FilterJointDef extends ffi.Struct {
  /// The first attached body.
  external b2BodyId bodyIdA;

  /// The second attached body.
  external b2BodyId bodyIdB;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// Prismatic joint definition
///
/// This requires defining a line of motion using an axis and an anchor point.
/// The definition uses local anchor points and a local axis so that the initial
/// configuration can violate the constraint slightly. The joint translation is zero
/// when the local anchor points coincide in world space.
/// @ingroup prismatic_joint
final class b2PrismaticJointDef extends ffi.Struct {
  /// The first attached body
  external b2BodyId bodyIdA;

  /// The second attached body
  external b2BodyId bodyIdB;

  /// The local anchor point relative to bodyA's origin
  external b2Vec2 localAnchorA;

  /// The local anchor point relative to bodyB's origin
  external b2Vec2 localAnchorB;

  /// The local translation unit axis in bodyA
  external b2Vec2 localAxisA;

  /// The constrained angle between the bodies: bodyB_angle - bodyA_angle
  @ffi.Float()
  external double referenceAngle;

  /// The target translation for the joint in meters. The spring-damper will drive
  /// to this translation.
  @ffi.Float()
  external double targetTranslation;

  /// Enable a linear spring along the prismatic joint axis
  @ffi.Bool()
  external bool enableSpring;

  /// The spring stiffness Hertz, cycles per second
  @ffi.Float()
  external double hertz;

  /// The spring damping ratio, non-dimensional
  @ffi.Float()
  external double dampingRatio;

  /// Enable/disable the joint limit
  @ffi.Bool()
  external bool enableLimit;

  /// The lower translation limit
  @ffi.Float()
  external double lowerTranslation;

  /// The upper translation limit
  @ffi.Float()
  external double upperTranslation;

  /// Enable/disable the joint motor
  @ffi.Bool()
  external bool enableMotor;

  /// The maximum motor force, typically in newtons
  @ffi.Float()
  external double maxMotorForce;

  /// The desired motor speed, typically in meters per second
  @ffi.Float()
  external double motorSpeed;

  /// Set this flag to true if the attached bodies should collide
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// Revolute joint definition
///
/// This requires defining an anchor point where the bodies are joined.
/// The definition uses local anchor points so that the
/// initial configuration can violate the constraint slightly. You also need to
/// specify the initial relative angle for joint limits. This helps when saving
/// and loading a game.
/// The local anchor points are measured from the body's origin
/// rather than the center of mass because:
/// 1. you might not know where the center of mass will be
/// 2. if you add/remove shapes from a body and recompute the mass, the joints will be broken
/// @ingroup revolute_joint
final class b2RevoluteJointDef extends ffi.Struct {
  /// The first attached body
  external b2BodyId bodyIdA;

  /// The second attached body
  external b2BodyId bodyIdB;

  /// The local anchor point relative to bodyA's origin
  external b2Vec2 localAnchorA;

  /// The local anchor point relative to bodyB's origin
  external b2Vec2 localAnchorB;

  /// The bodyB angle minus bodyA angle in the reference state (radians).
  /// This defines the zero angle for the joint limit.
  @ffi.Float()
  external double referenceAngle;

  /// The target angle for the joint in radians. The spring-damper will drive
  /// to this angle.
  @ffi.Float()
  external double targetAngle;

  /// Enable a rotational spring on the revolute hinge axis
  @ffi.Bool()
  external bool enableSpring;

  /// The spring stiffness Hertz, cycles per second
  @ffi.Float()
  external double hertz;

  /// The spring damping ratio, non-dimensional
  @ffi.Float()
  external double dampingRatio;

  /// A flag to enable joint limits
  @ffi.Bool()
  external bool enableLimit;

  /// The lower angle for the joint limit in radians. Minimum of -0.99*pi radians.
  @ffi.Float()
  external double lowerAngle;

  /// The upper angle for the joint limit in radians. Maximum of 0.99*pi radians.
  @ffi.Float()
  external double upperAngle;

  /// A flag to enable the joint motor
  @ffi.Bool()
  external bool enableMotor;

  /// The maximum motor torque, typically in newton-meters
  @ffi.Float()
  external double maxMotorTorque;

  /// The desired motor speed in radians per second
  @ffi.Float()
  external double motorSpeed;

  /// Scale the debug draw
  @ffi.Float()
  external double drawSize;

  /// Set this flag to true if the attached bodies should collide
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// Weld joint definition
///
/// A weld joint connect to bodies together rigidly. This constraint provides springs to mimic
/// soft-body simulation.
/// @note The approximate solver in Box2D cannot hold many bodies together rigidly
/// @ingroup weld_joint
final class b2WeldJointDef extends ffi.Struct {
  /// The first attached body
  external b2BodyId bodyIdA;

  /// The second attached body
  external b2BodyId bodyIdB;

  /// The local anchor point relative to bodyA's origin
  external b2Vec2 localAnchorA;

  /// The local anchor point relative to bodyB's origin
  external b2Vec2 localAnchorB;

  /// The bodyB angle minus bodyA angle in the reference state (radians)
  /// todo maybe make this a b2Rot
  @ffi.Float()
  external double referenceAngle;

  /// Linear stiffness expressed as Hertz (cycles per second). Use zero for maximum stiffness.
  @ffi.Float()
  external double linearHertz;

  /// Angular stiffness as Hertz (cycles per second). Use zero for maximum stiffness.
  @ffi.Float()
  external double angularHertz;

  /// Linear damping ratio, non-dimensional. Use 1 for critical damping.
  @ffi.Float()
  external double linearDampingRatio;

  /// Linear damping ratio, non-dimensional. Use 1 for critical damping.
  @ffi.Float()
  external double angularDampingRatio;

  /// Set this flag to true if the attached bodies should collide
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
  external ffi.Pointer<ffi.Void> userData;

  /// Used internally to detect a valid definition. DO NOT SET.
  @ffi.Int()
  external int internalValue;
}

/// Wheel joint definition
///
/// This requires defining a line of motion using an axis and an anchor point.
/// The definition uses local  anchor points and a local axis so that the initial
