/// @ingroup wheel_joint
final class b2WheelJointDef extends ffi.Struct {
  /// The first attached body
  external b2BodyId bodyIdA;

  /// The second attached body
  external b2BodyId bodyIdB;

  /// The local anchor point relative to bodyA's origin
  external b2Vec2 localAnchorA;

  /// The local anchor point relative to bodyB's origin
  external b2Vec2 localAnchorB;

  /// The local translation unit axis in bodyA
  external b2Vec2 localAxisA;

  /// Enable a linear spring along the local axis
  @ffi.Bool()
  external bool enableSpring;

  /// Spring stiffness in Hertz
  @ffi.Float()
  external double hertz;

  /// Spring damping ratio, non-dimensional
  @ffi.Float()
  external double dampingRatio;

  /// Enable/disable the joint linear limit
  @ffi.Bool()
  external bool enableLimit;

  /// The lower translation limit
  @ffi.Float()
  external double lowerTranslation;

  /// The upper translation limit
  @ffi.Float()
  external double upperTranslation;

  /// Enable/disable the joint rotational motor
  @ffi.Bool()
  external bool enableMotor;

  /// The maximum motor torque, typically in newton-meters
  @ffi.Float()
  external double maxMotorTorque;

  /// The desired motor speed in radians per second
  @ffi.Float()
  external double motorSpeed;

  /// Set this flag to true if the attached bodies should collide
  @ffi.Bool()
  external bool collideConnected;

  /// User data pointer
