/// The explosion definition is used to configure options for explosions. Explosions
/// consider shape geometry when computing the impulse.
/// @ingroup world
final class b2ExplosionDef extends ffi.Struct {
  /// Mask bits to filter shapes
  @ffi.Uint64()
  external int maskBits;

  /// The center of the explosion in world space
  external b2Vec2 position;

  /// The radius of the explosion
  @ffi.Float()
  external double radius;

  /// The falloff distance beyond the radius. Impulse is reduced to zero at this distance.
  @ffi.Float()
  external double falloff;

  /// Impulse per unit length. This applies an impulse according to the shape perimeter that
  /// is facing the explosion. Explosions only apply to circles, capsules, and polygons. This
  /// may be negative for implosions.
  @ffi.Float()
  external double impulsePerLength;
}

/// A begin touch event is generated when a shape starts to overlap a sensor shape.
final class b2SensorBeginTouchEvent extends ffi.Struct {
  /// The id of the sensor shape
  external b2ShapeId sensorShapeId;

  /// The id of the dynamic shape that began touching the sensor shape
  external b2ShapeId visitorShapeId;
}

/// An end touch event is generated when a shape stops overlapping a sensor shape.
/// These include things like setting the transform, destroying a body or shape, or changing
/// a filter. You will also get an end event if the sensor or visitor are destroyed.
/// Therefore you should always confirm the shape id is valid using b2Shape_IsValid.
final class b2SensorEndTouchEvent extends ffi.Struct {
  /// The id of the sensor shape
  /// @warning this shape may have been destroyed
  /// @see b2Shape_IsValid
  external b2ShapeId sensorShapeId;

  /// The id of the dynamic shape that stopped touching the sensor shape
  /// @warning this shape may have been destroyed
  /// @see b2Shape_IsValid
  external b2ShapeId visitorShapeId;
}

/// Sensor events are buffered in the Box2D world and are available
/// as begin/end overlap event arrays after the time step is complete.
/// Note: these may become invalid if bodies and/or shapes are destroyed
final class b2SensorEvents extends ffi.Struct {
  /// Array of sensor begin touch events
  external ffi.Pointer<b2SensorBeginTouchEvent> beginEvents;

  /// Array of sensor end touch events
  external ffi.Pointer<b2SensorEndTouchEvent> endEvents;

  /// The number of begin touch events
  @ffi.Int()
  external int beginCount;

  /// The number of end touch events
  @ffi.Int()
  external int endCount;
}

/// A begin touch event is generated when two shapes begin touching.
final class b2ContactBeginTouchEvent extends ffi.Struct {
  /// Id of the first shape
  external b2ShapeId shapeIdA;

  /// Id of the second shape
  external b2ShapeId shapeIdB;

  /// The initial contact manifold. This is recorded before the solver is called,
  /// so all the impulses will be zero.
  external b2Manifold manifold;
}

/// An end touch event is generated when two shapes stop touching.
/// You will get an end event if you do anything that destroys contacts previous to the last
/// world step. These include things like setting the transform, destroying a body
/// or shape, or changing a filter or body type.
final class b2ContactEndTouchEvent extends ffi.Struct {
  /// Id of the first shape
  /// @warning this shape may have been destroyed
  /// @see b2Shape_IsValid
  external b2ShapeId shapeIdA;

  /// Id of the second shape
  /// @warning this shape may have been destroyed
  /// @see b2Shape_IsValid
  external b2ShapeId shapeIdB;
}

/// A hit touch event is generated when two shapes collide with a speed faster than the hit speed threshold.
/// This may be reported for speculative contacts that have a confirmed impulse.
final class b2ContactHitEvent extends ffi.Struct {
  /// Id of the first shape
  external b2ShapeId shapeIdA;

  /// Id of the second shape
  external b2ShapeId shapeIdB;

  /// Point where the shapes hit at the beginning of the time step.
  /// This is a mid-point between the two surfaces. It could be at speculative
  /// point where the two shapes were not touching at the beginning of the time step.
  external b2Vec2 point;

  /// Normal vector pointing from shape A to shape B
  external b2Vec2 normal;

  /// The speed the shapes are approaching. Always positive. Typically in meters per second.
  @ffi.Float()
  external double approachSpeed;
}

/// Contact events are buffered in the Box2D world and are available
/// as event arrays after the time step is complete.
/// Note: these may become invalid if bodies and/or shapes are destroyed
final class b2ContactEvents extends ffi.Struct {
  /// Array of begin touch events
  external ffi.Pointer<b2ContactBeginTouchEvent> beginEvents;

  /// Array of end touch events
  external ffi.Pointer<b2ContactEndTouchEvent> endEvents;

  /// Array of hit events
  external ffi.Pointer<b2ContactHitEvent> hitEvents;

  /// Number of begin touch events
  @ffi.Int()
  external int beginCount;

  /// Number of end touch events
  @ffi.Int()
  external int endCount;

  /// Number of hit events
  @ffi.Int()
  external int hitCount;
}

/// Body move events triggered when a body moves.
/// Triggered when a body moves due to simulation. Not reported for bodies moved by the user.
/// This also has a flag to indicate that the body went to sleep so the application can also
/// sleep that actor/entity/object associated with the body.
/// On the other hand if the flag does not indicate the body went to sleep then the application
/// can treat the actor/entity/object associated with the body as awake.
/// This is an efficient way for an application to update game object transforms rather than
/// calling functions such as b2Body_GetTransform() because this data is delivered as a contiguous array
/// and it is only populated with bodies that have moved.
/// @note If sleeping is disabled all dynamic and kinematic bodies will trigger move events.
final class b2BodyMoveEvent extends ffi.Struct {
  external b2Transform transform;

  external b2BodyId bodyId;

  external ffi.Pointer<ffi.Void> userData;

  @ffi.Bool()
  external bool fellAsleep;
}

/// Body events are buffered in the Box2D world and are available
/// as event arrays after the time step is complete.
/// Note: this data becomes invalid if bodies are destroyed
final class b2BodyEvents extends ffi.Struct {
  /// Array of move events
  external ffi.Pointer<b2BodyMoveEvent> moveEvents;

  /// Number of move events
  @ffi.Int()
  external int moveCount;
}

/// The contact data for two shapes. By convention the manifold normal points
/// from shape A to shape B.
/// @see b2Shape_GetContactData() and b2Body_GetContactData()
final class b2ContactData extends ffi.Struct {
  external b2ShapeId shapeIdA;

  external b2ShapeId shapeIdB;

  external b2Manifold manifold;
}

/// Prototype for a contact filter callback.
/// This is called when a contact pair is considered for collision. This allows you to
/// perform custom logic to prevent collision between shapes. This is only called if
/// one of the two shapes has custom filtering enabled.
/// Notes:
/// - this function must be thread-safe
/// - this is only called if one of the two shapes has enabled custom filtering
/// - this is called only for awake dynamic bodies
/// Return false if you want to disable the collision
/// @see b2ShapeDef
/// @warning Do not attempt to modify the world inside this callback
/// @ingroup world
typedef b2CustomFilterFcn =
    ffi.NativeFunction<
      ffi.Bool Function(
        b2ShapeId shapeIdA,
        b2ShapeId shapeIdB,
        ffi.Pointer<ffi.Void> context,
      )
    >;

/// Prototype for a pre-solve callback.
/// This is called after a contact is updated. This allows you to inspect a
/// contact before it goes to the solver. If you are careful, you can modify the
/// contact manifold (e.g. modify the normal).
/// Notes:
/// - this function must be thread-safe
/// - this is only called if the shape has enabled pre-solve events
/// - this is called only for awake dynamic bodies
/// - this is not called for sensors
/// - the supplied manifold has impulse values from the previous step
/// Return false if you want to disable the contact this step
/// @warning Do not attempt to modify the world inside this callback
/// @ingroup world
typedef b2PreSolveFcn =
    ffi.NativeFunction<
      ffi.Bool Function(
        b2ShapeId shapeIdA,
        b2ShapeId shapeIdB,
        ffi.Pointer<b2Manifold> manifold,
        ffi.Pointer<ffi.Void> context,
      )
    >;

/// Prototype callback for overlap queries.
/// Called for each shape found in the query.
/// @see b2World_OverlapABB
/// @return false to terminate the query.
/// @ingroup world
typedef b2OverlapResultFcn =
    ffi.NativeFunction<
      ffi.Bool Function(b2ShapeId shapeId, ffi.Pointer<ffi.Void> context)
    >;

/// Prototype callback for ray and shape casts.
/// Called for each shape found in the query. You control how the ray cast
/// proceeds by returning a float:
/// return -1: ignore this shape and continue
/// return 0: terminate the ray cast
/// return fraction: clip the ray to this point
/// return 1: don't clip the ray and continue
/// A cast with initial overlap will return a zero fraction and a zero normal.
/// @param shapeId the shape hit by the ray
/// @param point the point of initial intersection
/// @param normal the normal vector at the point of intersection, zero for a shape cast with initial overlap
/// @param fraction the fraction along the ray at the point of intersection, zero for a shape cast with initial overlap
/// @param context the user context
/// @return -1 to filter, 0 to terminate, fraction to clip the ray for closest hit, 1 to continue
/// @see b2World_CastRay
/// @ingroup world
typedef b2CastResultFcn =
    ffi.NativeFunction<
      ffi.Float Function(
        b2ShapeId shapeId,
        b2Vec2 point,
        b2Vec2 normal,
        ffi.Float fraction,
        ffi.Pointer<ffi.Void> context,
      )
    >;

/// Used to collect collision planes for character movers.
/// Return true to continue gathering planes.
typedef b2PlaneResultFcn =
    ffi.NativeFunction<
      ffi.Bool Function(
        b2ShapeId shapeId,
        ffi.Pointer<b2PlaneResult> plane,
        ffi.Pointer<ffi.Void> context,
      )
    >;

/// These colors are used for debug draw and mostly match the named SVG colors.
/// See https://www.rapidtables.com/web/color/index.html
/// https://johndecember.com/html/spec/colorsvg.html
/// https://upload.wikimedia.org/wikipedia/commons/2/2b/SVG_Recognized_color_keyword_names.svg
enum b2HexColor {
  b2_colorAliceBlue(15792383),
