/// This struct holds callbacks you can implement to draw a Box2D world.
/// This structure should be zero initialized.
/// @ingroup world
final class b2DebugDraw extends ffi.Struct {
  /// Draw a closed polygon provided in CCW order.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        ffi.Pointer<b2Vec2> vertices,
        ffi.Int vertexCount,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawPolygonFcn;

  /// Draw a solid closed polygon provided in CCW order.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Transform transform,
        ffi.Pointer<b2Vec2> vertices,
        ffi.Int vertexCount,
        ffi.Float radius,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawSolidPolygonFcn;

  /// Draw a circle.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Vec2 center,
        ffi.Float radius,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawCircleFcn;

  /// Draw a solid circle.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Transform transform,
        ffi.Float radius,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawSolidCircleFcn;

  /// Draw a solid capsule.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Vec2 p1,
        b2Vec2 p2,
        ffi.Float radius,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawSolidCapsuleFcn;

  /// Draw a line segment.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Vec2 p1,
        b2Vec2 p2,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawSegmentFcn;

  /// Draw a transform. Choose your own length scale.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(b2Transform transform, ffi.Pointer<ffi.Void> context)
    >
  >
  DrawTransformFcn;

  /// Draw a point.
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Vec2 p,
        ffi.Float size,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawPointFcn;

  /// Draw a string in world space
  external ffi.Pointer<
    ffi.NativeFunction<
      ffi.Void Function(
        b2Vec2 p,
        ffi.Pointer<ffi.Char> s,
        ffi.UnsignedInt color,
        ffi.Pointer<ffi.Void> context,
      )
    >
  >
  DrawStringFcn;

  /// Bounds to use if restricting drawing to a rectangular region
  external b2AABB drawingBounds;

  /// Option to restrict drawing to a rectangular region. May suffer from unstable depth sorting.
  @ffi.Bool()
  external bool useDrawingBounds;

  /// Option to draw shapes
  @ffi.Bool()
  external bool drawShapes;

  /// Option to draw joints
  @ffi.Bool()
  external bool drawJoints;

  /// Option to draw additional information for joints
  @ffi.Bool()
  external bool drawJointExtras;

  /// Option to draw the bounding boxes for shapes
  @ffi.Bool()
  external bool drawBounds;

  /// Option to draw the mass and center of mass of dynamic bodies
  @ffi.Bool()
  external bool drawMass;

  /// Option to draw body names
  @ffi.Bool()
  external bool drawBodyNames;

  /// Option to draw contact points
  @ffi.Bool()
  external bool drawContacts;

  /// Option to visualize the graph coloring used for contacts and joints
  @ffi.Bool()
  external bool drawGraphColors;

  /// Option to draw contact normals
  @ffi.Bool()
  external bool drawContactNormals;

  /// Option to draw contact normal impulses
  @ffi.Bool()
  external bool drawContactImpulses;

  /// Option to draw contact feature ids
  @ffi.Bool()
  external bool drawContactFeatures;

  /// Option to draw contact friction impulses
  @ffi.Bool()
  external bool drawFrictionImpulses;

  /// Option to draw islands as bounding boxes
  @ffi.Bool()
  external bool drawIslands;

  /// User context that is passed as an argument to drawing callback functions
  external ffi.Pointer<ffi.Void> context;
}

const int B2_HASH_INIT = 5381;

const double B2_PI = 3.1415927410125732;

const int B2_MAX_POLYGON_VERTICES = 8;

const int B2_DEFAULT_CATEGORY_BITS = 1;

const int B2_DEFAULT_MASK_BITS = -1;
